PrologProcedure:
################################################################################
# META DATA GBL Period
#
# Structure:
#   All Periods
#   ├── All FY
#   │   └── All FY22 - All FY27
#   │       ├── FY22 MTD > monthly MTD consolidations (OBL + months)
#   │       ├── FY22 YTG > monthly YTG consolidations
#   │       └── FY22     > OBL + leaf months
#   ├── All CY
#   │   └── CY2021 - CY2027
#   └── All System
#       └── All OBL > FY22 OBL - FY27 OBL
#
# Attributes:
#   Alias            A   e.g. Apr 26
#   Prior Period     S   previous period element name
#   Next Period      S   next period element name
#   FY Month Number  N   1-12 (April = 1)
#   FY               S   e.g. FY26
#   Date Serial SOM  N   DateSerial of first day of month
#   Date Serial EOM  N   DateSerial of last day of month
#   Days in Month    N   actual days in month
#   Is Open          S   Y or N
#   Is Current       S   Y or N
#
# Module:  GBL
# Author:  TM1 Governance Project
# Version: 1.0
# Date:    March 2026
################################################################################

DimName     = 'GBL Period';
sYear       = '';
sMonth      = '';
sElement    = '';
sAlias      = '';
sMonthName  = '';
sMonthNames = 'Jan,Feb,Mar,Apr,May,Jun,Jul,Aug,Sep,Oct,Nov,Dec';
nYear       = 0;
nMonth      = 0;
nFY         = 0;
nFYYear     = 0;
nFYMonth    = 0;
sFY         = '';
sAllFY      = '';
sCY         = '';
sOBL        = '';
sMTDGroup   = '';
sYTGGroup   = '';
sMTDEl      = '';
sYTGEl      = '';
nMTDMonth   = 0;
nYTGMonth   = 0;
nFYMonthNum = 0;
nSOM        = 0;
nEOM        = 0;
nDays       = 0;
sPrior      = '';
sNext       = '';

# Days per month lookup (non-leap: 31,28,31,30,31,30,31,31,30,31,30,31)
# We will calculate using DateSerial difference

IF( DimensionExists( DimName ) = 1 );
    DimensionDeleteAllElements( DimName );
ELSE;
    DimensionCreate( DimName );
ENDIF;

# ------------------------------------------------------------------------------
# Attributes
# ------------------------------------------------------------------------------
AttrDelete( DimName, 'Alias' );
AttrInsert( DimName, '', 'Alias', 'A' );

AttrDelete( DimName, 'Prior Period' );
AttrInsert( DimName, 'Alias', 'Prior Period', 'S' );

AttrDelete( DimName, 'Next Period' );
AttrInsert( DimName, 'Prior Period', 'Next Period', 'S' );

AttrDelete( DimName, 'FY' );
AttrInsert( DimName, 'Next Period', 'FY', 'S' );

AttrDelete( DimName, 'FY Month Number' );
AttrInsert( DimName, 'FY', 'FY Month Number', 'N' );

AttrDelete( DimName, 'Date Serial SOM' );
AttrInsert( DimName, 'FY Month Number', 'Date Serial SOM', 'N' );

AttrDelete( DimName, 'Date Serial EOM' );
AttrInsert( DimName, 'Date Serial SOM', 'Date Serial EOM', 'N' );

AttrDelete( DimName, 'Days in Month' );
AttrInsert( DimName, 'Date Serial EOM', 'Days in Month', 'N' );

AttrDelete( DimName, 'Is Open' );
AttrInsert( DimName, 'Days in Month', 'Is Open', 'S' );

AttrDelete( DimName, 'Is Current' );
AttrInsert( DimName, 'Is Open', 'Is Current', 'S' );

# ------------------------------------------------------------------------------
# Top level structure
# ------------------------------------------------------------------------------
DimensionElementInsert( DimName, '', 'All Periods', 'C' );

DimensionElementInsert( DimName, '', 'All FY', 'C' );
DimensionElementComponentAdd( DimName, 'All Periods', 'All FY', 1 );

DimensionElementInsert( DimName, '', 'All CY', 'C' );
DimensionElementComponentAdd( DimName, 'All Periods', 'All CY', 1 );

DimensionElementInsert( DimName, '', 'All System', 'C' );
DimensionElementComponentAdd( DimName, 'All Periods', 'All System', 1 );

DimensionElementInsert( DimName, '', 'All OBL', 'C' );
DimensionElementComponentAdd( DimName, 'All System', 'All OBL', 1 );

# ------------------------------------------------------------------------------
# CY consolidations
# ------------------------------------------------------------------------------
nYear = 2021;
WHILE( nYear <= 2027 );
    sCY = 'CY' | NumberToString( nYear );
    DimensionElementInsert( DimName, '', sCY, 'C' );
    DimensionElementComponentAdd( DimName, 'All CY', sCY, 1 );
    nYear = nYear + 1;
END;

# ------------------------------------------------------------------------------
# FY loop — build All FYxx, FYxx MTD, FYxx YTG, FYxx, OBL
# ------------------------------------------------------------------------------
nFY = 22;
WHILE( nFY <= 27 );

    sFY       = 'FY' | NumberToString( nFY );
    sAllFY    = 'All FY' | NumberToString( nFY );
    sOBL      = sFY | ' OBL';
    sMTDGroup = sFY | ' MTD';
    sYTGGroup = sFY | ' YTG';
    nFYYear   = nFY + 1999;

    # All FYxx wrapper
    DimensionElementInsert( DimName, '', sAllFY, 'C' );
    DimensionElementComponentAdd( DimName, 'All FY', sAllFY, 1 );

    # MTD group under All FYxx
    DimensionElementInsert( DimName, '', sMTDGroup, 'C' );
    DimensionElementComponentAdd( DimName, sAllFY, sMTDGroup, 1 );

    # YTG group under All FYxx
    DimensionElementInsert( DimName, '', sYTGGroup, 'C' );
    DimensionElementComponentAdd( DimName, sAllFY, sYTGGroup, 1 );

    # FY consolidation under All FYxx
    DimensionElementInsert( DimName, '', sFY, 'C' );
    DimensionElementComponentAdd( DimName, sAllFY, sFY, 1 );

    # OBL leaf
    DimensionElementInsert( DimName, '', sOBL, 'N' );
    AttrPutS( sOBL, DimName, sOBL, 'Alias' );
    AttrPutS( sFY,  DimName, sOBL, 'FY' );
    AttrPutS( 'N',  DimName, sOBL, 'Is Open' );
    AttrPutS( 'N',  DimName, sOBL, 'Is Current' );
    DimensionElementComponentAdd( DimName, 'All OBL', sOBL, 1 );
    DimensionElementComponentAdd( DimName, sFY, sOBL, 1 );

    # MTD and YTG monthly consolidations
    nFYMonth = 4;
    WHILE( nFYMonth <= 15 );
        IF( nFYMonth <= 12 );
            nYear  = nFYYear;
            nMonth = nFYMonth;
        ELSE;
            nYear  = nFYYear + 1;
            nMonth = nFYMonth - 12;
        ENDIF;
        sMonthName = SubSt( sMonthNames, ( nMonth - 1 ) * 4 + 1, 3 );

        # MTD consolidation
        sMTDEl = sFY | ' ' | sMonthName | ' MTD';
        DimensionElementInsert( DimName, '', sMTDEl, 'C' );
        DimensionElementComponentAdd( DimName, sMTDGroup, sMTDEl, 1 );
        DimensionElementComponentAdd( DimName, sMTDEl, sOBL, 1 );
        nMTDMonth = 4;
        WHILE( nMTDMonth <= nFYMonth );
            IF( nMTDMonth <= 12 );
                sYear = NumberToString( nFYYear );
                IF( nMTDMonth < 10 );
                    sMonth = '0' | NumberToString( nMTDMonth );
                ELSE;
                    sMonth = NumberToString( nMTDMonth );
                ENDIF;
            ELSE;
                sYear = NumberToString( nFYYear + 1 );
                IF( nMTDMonth - 12 < 10 );
                    sMonth = '0' | NumberToString( nMTDMonth - 12 );
                ELSE;
                    sMonth = NumberToString( nMTDMonth - 12 );
                ENDIF;
            ENDIF;
            DimensionElementComponentAdd( DimName, sMTDEl, sYear | sMonth, 1 );
            nMTDMonth = nMTDMonth + 1;
        END;

        # YTG consolidation
        sYTGEl = sFY | ' ' | sMonthName | ' YTG';
        DimensionElementInsert( DimName, '', sYTGEl, 'C' );
        DimensionElementComponentAdd( DimName, sYTGGroup, sYTGEl, 1 );
        nYTGMonth = nFYMonth;
        WHILE( nYTGMonth <= 15 );
            IF( nYTGMonth <= 12 );
                sYear = NumberToString( nFYYear );
                IF( nYTGMonth < 10 );
                    sMonth = '0' | NumberToString( nYTGMonth );
                ELSE;
                    sMonth = NumberToString( nYTGMonth );
                ENDIF;
            ELSE;
                sYear = NumberToString( nFYYear + 1 );
                IF( nYTGMonth - 12 < 10 );
                    sMonth = '0' | NumberToString( nYTGMonth - 12 );
                ELSE;
                    sMonth = NumberToString( nYTGMonth - 12 );
                ENDIF;
            ENDIF;
            DimensionElementComponentAdd( DimName, sYTGEl, sYear | sMonth, 1 );
            nYTGMonth = nYTGMonth + 1;
        END;

        nFYMonth = nFYMonth + 1;
    END;

    # Leaf months for this FY
    nYear = nFYYear;
    WHILE( nYear <= nFYYear + 1 );
        nMonth = 1;
        WHILE( nMonth <= 12 );
            IF( nYear = nFYYear & nMonth < 4 );
                nMonth = nMonth + 1;
            ELSEIF( nYear = nFYYear + 1 & nMonth > 3 );
                nMonth = 13;
            ELSE;
                sYear = NumberToString( nYear );
                IF( nMonth < 10 );
                    sMonth = '0' | NumberToString( nMonth );
                ELSE;
                    sMonth = NumberToString( nMonth );
                ENDIF;
                sElement   = sYear | sMonth;
                sMonthName = SubSt( sMonthNames, ( nMonth - 1 ) * 4 + 1, 3 );
                sAlias     = sMonthName | ' ' | SubSt( sYear, 3, 2 );

                # FY Month Number (April=1)
                IF( nMonth >= 4 );
                    nFYMonthNum = nMonth - 3;
                ELSE;
                    nFYMonthNum = nMonth + 9;
                ENDIF;

                # DateSerial SOM and EOM
                # nSOM  = DateSerial( nYear, nMonth, 1 );
                # IF( nMonth = 12 );
                #     nEOM = DateSerial( nYear + 1, 1, 1 ) - 1;
                # ELSE;
                #     nEOM = DateSerial( nYear, nMonth + 1, 1 ) - 1;
                # ENDIF;
                # nDays = nEOM - nSOM + 1;
                
                sNextMonthFirst = DATES( nYear + INT((nMonth)/12), MOD(nMonth, 12) + 1, 1 );
                nEOM = DayNo( sNextMonthFirst ) - 1;
                nSOM = DayNo( DATES( nYear, nMonth, 1 ) );
                nDays = nEOM - nSOM + 1;


                IF( DimensionElementExists( DimName, sElement ) = 0 );
                    DimensionElementInsert( DimName, '', sElement, 'N' );
                    AttrPutS( sAlias,              DimName, sElement, 'Alias' );
                    AttrPutS( sFY,                 DimName, sElement, 'FY' );
                    AttrPutN( nFYMonthNum,          DimName, sElement, 'FY Month Number' );
                    AttrPutN( nSOM,                 DimName, sElement, 'Date Serial SOM' );
                    AttrPutN( nEOM,                 DimName, sElement, 'Date Serial EOM' );
                    AttrPutN( nDays,                DimName, sElement, 'Days in Month' );
                    AttrPutS( 'N',                  DimName, sElement, 'Is Open' );
                    AttrPutS( 'N',                  DimName, sElement, 'Is Current' );
                    sCY = 'CY' | sYear;
                    DimensionElementComponentAdd( DimName, sCY, sElement, 1 );
                ENDIF;
                DimensionElementComponentAdd( DimName, sFY, sElement, 1 );
                nMonth = nMonth + 1;
            ENDIF;
        END;
        nYear = nYear + 1;
    END;

    nFY = nFY + 1;
END;

# ------------------------------------------------------------------------------
# Prior Period and Next Period attributes
# Loop through all leaf elements in date order and set prior/next
# ------------------------------------------------------------------------------
nYear = 2021;
WHILE( nYear <= 2027 );
    nMonth = 1;
    WHILE( nMonth <= 12 );
        IF( nYear = 2027 & nMonth > 3 );
            nMonth = 13;
        ELSE;
            sYear = NumberToString( nYear );
            IF( nMonth < 10 );
                sMonth = '0' | NumberToString( nMonth );
            ELSE;
                sMonth = NumberToString( nMonth );
            ENDIF;
            sElement = sYear | sMonth;

            # Prior Period
            IF( nMonth = 4 );
                # First month of FY - prior is OBL
                IF( nYear >= 2021 );
                    nFY = nYear - 1999;
                ENDIF;
                sFY    = 'FY' | NumberToString( nFY );
                sPrior = sFY | ' OBL';
            ELSEIF( nYear = 2021 & nMonth = 1 );
                sPrior = '';
            ELSE;
                IF( nMonth = 1 );
                    sPrior = NumberToString( nYear - 1 ) | '12';
                ELSEIF( nMonth < 10 );
                    sPrior = sYear | '0' | NumberToString( nMonth - 1 );
                ELSE;
                    sPrior = sYear | NumberToString( nMonth - 1 );
                ENDIF;
            ENDIF;

            # Next Period
            IF( nYear = 2027 & nMonth = 3 );
                sNext = '';
            ELSEIF( nMonth = 12 );
                sNext = NumberToString( nYear + 1 ) | '01';
            ELSEIF( nMonth < 9 );
                sNext = sYear | '0' | NumberToString( nMonth + 1 );
            ELSE;
                sNext = sYear | NumberToString( nMonth + 1 );
            ENDIF;

            AttrPutS( sPrior, DimName, sElement, 'Prior Period' );
            AttrPutS( sNext,  DimName, sElement, 'Next Period' );

            # Set Next Period on OBL to point to Apr of that FY
            IF( nMonth = 4 );
                IF( nYear >= 2021 );
                    nFY = nYear - 1999;
                ENDIF;
                sFY  = 'FY' | NumberToString( nFY );
                sOBL = sFY | ' OBL';
                AttrPutS( sElement, DimName, sOBL, 'Next Period' );
            ENDIF;

            nMonth = nMonth + 1;
        ENDIF;
    END;
    nYear = nYear + 1;
END;

ProcessBreak;
